	@Test
	void getRiskSignals_requiresActorHeader() throws Exception {
		mockMvc.perform(get("/api/plans/" + UUID.randomUUID() + "/risk-signals")).andExpect(status().isBadRequest());
	}

	@Test
	void getRiskSignals_usesActorHeaderForPrivacyCheckedLookup() throws Exception {
		UUID planId = UUID.randomUUID();
		UUID callerId = UUID.randomUUID();
		PlanRiskSignals response = new PlanRiskSignals(true, planId, List
				.of(new RiskSignalResponse(UUID.randomUUID(), "OVERCOMMIT", "rationale", planId, null, Instant.now())));
		when(riskDetectionService.getRiskSignals(eq(planId), eq(callerId))).thenReturn(response);

		mockMvc.perform(get("/api/plans/" + planId + "/risk-signals").header("X-Actor-User-Id", callerId.toString()))
				.andExpect(status().isOk()).andExpect(jsonPath("$.planId").value(planId.toString()))
				.andExpect(jsonPath("$.signals[0].signalType").value("OVERCOMMIT"));

		verify(riskDetectionService).getRiskSignals(planId, callerId);
	}
}

package com.weeklycommit.ai.dto;

import java.time.Instant;
import java.util.List;
import java.util.UUID;

/**
 * Risk signal detected for a plan (stored in {@code ai_suggestion} with type
 * {@code RISK_SIGNAL}).
 *
 * <p>
 * Risk signals are hidden from peers; only the plan owner and their manager may
 * view them.
 */
public record RiskSignalResponse(
		/** Suggestion id (for feedback/dismiss). */
		UUID id,
		/** Signal type code (e.g., OVERCOMMIT, UNDERCOMMIT, REPEATED_CARRY_FORWARD). */
		String signalType,
		/** Human-readable rationale explaining why this signal was raised. */
		String rationale,
		/** Plan the signal relates to. */
		UUID planId,
		/** Specific commit the signal relates to (null for plan-level signals). */
		UUID commitId,
		/** When the signal was generated. */
		Instant createdAt) {

	/** Wraps a list of risk signals with the plan-level available flag. */
	public record PlanRiskSignals(boolean aiAvailable, UUID planId, List<RiskSignalResponse> signals) {

		public static PlanRiskSignals unavailable(UUID planId) {
			return new PlanRiskSignals(false, planId, List.of());
		}
	}
}

